import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import {Button, H1, H2, Tab, Tabs} from "@blueprintjs/core";
import { observer } from "mobx-react";
import { Register } from "./Register";
import { Login } from "./Login";

export const Welcome: FunctionComponent<{ default_tab: string }> = props => {
  const [tab, setTab] = useState(props.default_tab);
  // const test: string = ctx.store.menu;
  return (
    <div className="body center">
      <div className="fx -r">
        <div className="curve-border" aria-setsize={50}>
            <H2 className="title-primary">Heabank</H2>
            <p className="helvetica">Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod tempor incididunt ut labore
                et dolore magna aliqua.
                Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod tempor incididunt ut labore
                et dolore magna aliqua.Lorem ipsum dolor sit amet, consectetur adipisicing elit, sed do eiusmod tempor
                incididunt ut labore et dolore magna aliqua. Lorem ipsum dolor sit amet, consectetur adipisicing elit,
                sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.</p>
        </div>
        <div className="curve-border">
          <Tabs id="TabsExample" selectedTabId={tab} className="outline-style-d">
            <Tab
              id="lg"
              title="Login"
              onClickCapture={() => setTab("lg")}
              panel={<Login />}
              panelClassName="test-panel"
            />
            <Tab
              id="rg"
              title="Register"
              onClickCapture={() => setTab("rg")}
              panel={<Register />}
              panelClassName="ember-panel"
            />
            <Tabs.Expander />
          </Tabs>
        </div>
      </div>
    </div>
  );
};
